INSERT INTO marathons ("id", "name", "canonical_name", "city", "country", "description", "website_url", "created_at", "updated_at") VALUES
  ('530aea1b-8b8c-44a1-8ac3-2ad1ac124ed6', '2026首届长兴太湖9号公路玫瑰跑嘉年华', 'changxing-taihu-rose-run-2026', '湖州', 'China', '沿太湖浪漫公路展开的花海跑，兼顾城市与自然风景。春季花瓣节式氛围，适合亲子与新手体验。', NULL, '2026-03-07T02:54:45.11847+00:00', '2026-03-07T02:54:45.087+00:00'),
  ('bf1b255b-ba40-48ac-b310-fda405d683e1', '2026上海樱花节女子10公里精英赛', 'shanghai-cherry-blossom-run-2026', '上海', 'China', '滨江公益10公里，穿越宝山新城与樱花大道。清晨日出启跑，连接企业跑团与社区的慈善氛围。', 'https://shanghai-cherry-run.example.com', '2026-03-07T02:54:45.128889+00:00', '2026-03-07T02:54:45.127+00:00'),
  ('5f97e369-e688-4b27-b6ee-138add748c67', '2026武汉空港国际商务新城半程马拉松', 'wuhan-airport-half-marathon-2026', '武汉', 'China', '环武汉空港商务区的半程马，夜色下有灯光长廊与打卡点。江边赛道深受区域跑团与航空业员工欢迎。', NULL, '2026-03-07T02:54:45.135416+00:00', '2026-03-07T02:54:45.133+00:00'),
  ('02d260f3-4073-4243-aaef-01b6e237ca98', '2026曲靖罗平花海马拉松', 'qujing-luoping-flower-sea-marathon-2026', '曲靖', 'China', '在罗平花海与山峦之间展开的高海拔全程马拉松，空气清新，坡道与花海交错。', 'http://qujing-marathon.example.com', '2026-03-07T02:54:45.140918+00:00', '2026-03-07T02:54:45.14+00:00'),
  ('f626e003-b26f-4690-9489-8c8e6076e49f', '2026重庆万州环湖马拉松', 'chongqing-wanzhou-lake-marathon-2026', '万州', 'China', '环绕万州湖泊的全程与半程双赛事，并配套当代艺术主题展。艺术周氛围浓厚，路跑与现场演出同步进行。', NULL, '2026-03-07T02:54:45.146636+00:00', '2026-03-07T02:54:45.145+00:00'),
  ('3e28c296-7eca-4d63-a681-b5dad69e32e8', '2026临平半程马拉松', 'linping-half-marathon-2026', '杭州', 'China', '贯穿临平中心区的夜半程与10公里联赛，灯光与运河交织，提供轻松节奏与能量补给。', NULL, '2026-03-07T02:54:45.151674+00:00', '2026-03-07T02:54:45.151+00:00'),
  ('37a9f526-40a8-4542-b4cc-113af3a0e59d', '2026贵州·仁怀马拉松', 'guizhou-renhuai-marathon-2026', '仁怀', 'China', '沿湿地与森林的小径展开的仁怀全程马拉松，兼顾生态观光，展示红泥土与鸟类生态。', NULL, '2026-03-07T02:54:45.157061+00:00', '2026-03-07T02:54:45.156+00:00'),
  ('03ad513a-639d-44b3-9828-bb6aa27c74eb', '2026南京溧水半程马拉松', 'nanjing-lishui-half-marathon-2026', '南京', 'China', '溧水植物园半马，穿梭湖畔与温室花房，晚春花木盛开适合俱乐部组团。', NULL, '2026-03-07T02:54:45.162661+00:00', '2026-03-07T02:54:45.162+00:00'),
  ('45c4f0e6-dbd7-4904-a874-7a5be4b5dfc5', '2026东京马拉松', 'tokyo-marathon-2026', '东京', 'Japan', '世界六大满贯之一，清晨从皇居出发穿越都市核心，沿途樱花点缀。', 'https://www.marathon.tokyo/en/', '2026-03-07T02:54:45.168409+00:00', '2026-03-07T02:54:45.167+00:00'),
  ('bb8677ed-4c8d-4928-9762-fb5e8ecbb651', '2026巴黎马拉松', 'paris-marathon-2026', '巴黎', 'France', '沿塞纳河跑过卢浮宫与凯旋门的浪漫路线，赛前暖场由巴黎街头乐队与艺术团体助威。', 'https://www.schneiderelectricparismarathon.com/en/', '2026-03-07T02:54:45.174059+00:00', '2026-03-07T02:54:45.173+00:00'),
  ('4fbae442-11de-4e20-93e4-fd0fc5076d7d', '2026波士顿马拉松', 'boston-marathon-2026', '波士顿', 'USA', '历史最悠久的马拉松，以严格的BQ资格闻名，挑战换道山与心跳山中段。', 'https://www.baa.org/races/boston-marathon', '2026-03-07T02:54:45.179341+00:00', '2026-03-07T02:54:45.178+00:00'),
  ('ad3e91c8-b48e-4fc3-9003-a8ff31be8c90', '2026柏林马拉松', 'berlin-marathon-2026', '柏林', 'Germany', '世界纪录之路，现代化城市景观与平坦路段兼具，柏林墙与广场串联赛道。', 'https://www.bmw-berlin-marathon.com/en/', '2026-03-07T02:54:45.190204+00:00', '2026-03-07T02:54:45.189+00:00'),
