  ('be4e78a3-3da6-4530-8f00-44350c24308d', '2026纽约城市马拉松', 'new-york-city-marathon-2026', '纽约', 'USA', '串联五大区的大型马拉松，路线跨越多座桥梁，群众声浪与街头乐队相伴。', 'https://www.tcsnycmarathon.org/', '2026-03-07T02:54:45.200215+00:00', '2026-03-07T02:54:45.199+00:00'),
  ('5f7ae5ab-bf47-46d2-bd73-ffcd829d0fec', '2026伦敦马拉松', 'london-marathon-2026', '伦敦', 'UK', '沿泰晤士河与皇家公园的慈善盛事路线，起点于泰晤士桥后进入绿茵皇家公园。', 'https://www.tcslondonmarathon.com/', '2026-03-07T02:54:45.184882+00:00', '2026-03-07T02:54:45.184+00:00'),
  ('315803d1-400d-411a-83fe-33e2dc822a5c', '2026悉尼马拉松', 'sydney-marathon-2026', '悉尼', 'Australia', '南半球新晋大满贯赛事，沿悉尼海港大桥与歌剧院展开，南半球春季氛围。', 'https://sydneymarathon.com/', '2026-05-02T14:54:41.330373+00:00', '2026-05-02T14:54:41.330373+00:00'),
  ('a4894f9a-2ef9-48a4-9df1-8fe0ef0b1e4a', '2026开普敦马拉松', 'cape-town-marathon-2026', '开普敦', 'South Africa', '世界大满贯候选赛事，开普敦城市赛道兼顾桌山与海岸景观。', 'https://capetownmarathon.com/', '2026-05-02T14:54:41.330373+00:00', '2026-05-02T14:54:41.330373+00:00'),
