  ('97c3b474-c114-440a-bc70-bd41cc2d1681', '2026广州马拉松', 'guangzhou-marathon-2026', '广州', 'China', '冬季暖意宜人的珠江赛道，国际跑者欢迎，城市规划成熟。', 'http://www.guangzhou-marathon.com/', '2026-05-02T14:54:41.330373+00:00', '2026-05-02T14:54:41.330373+00:00'),
  ('92b88ab7-4ded-4055-8d7a-48faa301aaa6', '2027厦门马拉松', 'xiamen-marathon-2027', '厦门', 'China', '世界田联金标，新年元月开跑、环岛海岸风光，老牌精品赛事。', 'https://www.xmim.org/', '2026-05-02T14:54:41.330373+00:00', '2026-05-02T14:54:41.330373+00:00'),
