-- =============================================================================
-- 生产库初始化脚本（从 dev 库 2026-05-02 全量导出）
-- 表：sources(20) / marathons(37) / marathon_editions(41) / marathon_sources(45)
-- 用法：psql "$PROD_DATABASE_URL" -f docs/数据库变更/2026-05-02c-prod-initial-seed.sql
-- 幂等：基于 (canonical_name)/(name)/(marathon_id,year)/(marathon_id,source_id) 的 ON CONFLICT 处理
-- 假设：prod 库已存在 schema（marathons/marathon_editions/sources/marathon_sources 等表）
-- =============================================================================

BEGIN;

-- 1) sources
ON CONFLICT ("name") DO UPDATE SET "type" = EXCLUDED."type", "strategy" = EXCLUDED."strategy", "base_url" = EXCLUDED."base_url", "priority" = EXCLUDED."priority", "is_active" = EXCLUDED."is_active", "retry_max" = EXCLUDED."retry_max", "retry_backoff_seconds" = EXCLUDED."retry_backoff_seconds", "request_timeout_ms" = EXCLUDED."request_timeout_ms", "min_interval_seconds" = EXCLUDED."min_interval_seconds", "notes" = EXCLUDED."notes", "config" = EXCLUDED."config", "updated_at" = NOW();

-- 2) marathons
ON CONFLICT ("canonical_name") DO UPDATE SET "name" = EXCLUDED."name", "city" = EXCLUDED."city", "country" = EXCLUDED."country", "description" = EXCLUDED."description", "website_url" = EXCLUDED."website_url", "updated_at" = NOW();

-- 3) marathon_editions
ON CONFLICT ("marathon_id", "year") DO UPDATE SET "race_date" = EXCLUDED."race_date", "registration_status" = EXCLUDED."registration_status", "registration_url" = EXCLUDED."registration_url", "registration_open_date" = EXCLUDED."registration_open_date", "registration_close_date" = EXCLUDED."registration_close_date", "publish_status" = EXCLUDED."publish_status", "published_at" = EXCLUDED."published_at", "field_sources" = EXCLUDED."field_sources", "last_synced_at" = EXCLUDED."last_synced_at", "next_sync_at" = EXCLUDED."next_sync_at", "updated_at" = NOW();

-- 4) marathon_sources
ON CONFLICT ("marathon_id", "source_id") DO UPDATE SET "source_url" = EXCLUDED."source_url", "is_primary" = EXCLUDED."is_primary", "last_checked_at" = EXCLUDED."last_checked_at", "last_hash" = EXCLUDED."last_hash", "last_http_status" = EXCLUDED."last_http_status", "last_error" = EXCLUDED."last_error", "next_check_at" = EXCLUDED."next_check_at", "updated_at" = NOW();

-- 5) 校验
SELECT 'sources' AS t, COUNT(*) AS n FROM sources
  UNION ALL SELECT 'marathons', COUNT(*) FROM marathons
  UNION ALL SELECT 'marathon_editions', COUNT(*) FROM marathon_editions
  UNION ALL SELECT 'marathon_sources', COUNT(*) FROM marathon_sources;

COMMIT;
